from atomic_agents import BaseIOSchema

class ResearchQuery(BaseIOSchema):
    topic: str

class ResearchNotes(BaseIOSchema):
    notes: str
    sources: list[str]

class Article(BaseIOSchema):
    title: str
    body: str

# Agent 1: gather research
researcher = BaseAgent(
    config=BaseAgentConfig(
        client=client, model="gpt-4o",
        input_schema=ResearchQuery, output_schema=ResearchNotes,
    )
)

# Agent 2: write article from notes
writer = BaseAgent(
    config=BaseAgentConfig(
        client=client, model="gpt-4o",
        input_schema=ResearchNotes, output_schema=Article,
    )
)

def research_and_write(topic: str) -> Article:
    notes = researcher.run(ResearchQuery(topic=topic))
    return writer.run(notes)   # ResearchNotes is the input schema for writer
